const PROVIDER_STYLES: Record<string, string> = {
  google:
    "bg-white text-[#1f1f1f] border-[rgba(255,255,255,0.12)] hover:bg-[#f8f8f8] shadow-[0_1px_3px_rgba(0,0,0,0.08)]",
  discord:
    "bg-[#5865F2] text-white border-[rgba(88,101,242,0.3)] hover:bg-[#4752C4] shadow-[0_1px_3px_rgba(88,101,242,0.2)]",
  microsoft:
    "bg-[#2F2F2F] text-white border-[rgba(255,255,255,0.08)] hover:bg-[#3a3a3a] shadow-[0_1px_3px_rgba(0,0,0,0.12)]",
}

const SocialButton: React.FC<{
  provider: OAuthProvider
  onClick: () => void
  disabled: boolean
  variant: string
}> = ({ provider, onClick, disabled, variant }) => {
  const config = OAUTH_PROVIDERS[provider]
  const Icon = SocialIcons[config.icon as keyof typeof SocialIcons]

  const getButtonText = () => {
    switch (variant) {
      case "register":
        return `Sign up with ${config.name}`
      case "link":
        return `Link ${config.name}`
      default:
        return `Continue with ${config.name}`
    }
  }

  return (
    <button
      className={cn(
        "w-full flex items-center justify-center gap-3 h-12 text-sm font-medium rounded-[14px] border transition-colors disabled:opacity-50",
        PROVIDER_STYLES[provider] ?? ""
      )}
      onClick={onClick}
      disabled={disabled}
    >
      <Icon />
      <span>{getButtonText()}</span>
    </button>
  )
}

export const SocialLoginButtons: React.FC<SocialLoginButtonsProps> = ({
  returnUrl,
  className = "",
  disabled = false,
  variant = "login",
  onError,
}) => {
  const [loadingProvider, setLoadingProvider] = useState<OAuthProvider | null>(null)

  const handleSocialLogin = async (provider: OAuthProvider) => {
    if (disabled || loadingProvider) return

    try {
      setLoadingProvider(provider)
      await initiateOAuthLogin(provider, returnUrl)
    } catch (error: any) {
      console.error(`${provider} login error:`, error)
      onError?.(error.message || `Failed to initiate ${provider} login`)
      setLoadingProvider(null)
    }
  }

  const providers: OAuthProvider[] = ["google", "discord", "microsoft"]

  return (
    <div className={cn("space-y-3", className)}>
      <div className="grid grid-cols-1 gap-3">
        {providers.map((provider) => (
          <SocialButton
            key={provider}
            provider={provider}
            onClick={() => handleSocialLogin(provider)}
            disabled={disabled || loadingProvider === provider}
            variant={variant}
          />
        ))}
      </div>

      {loadingProvider && (
        <div className="text-center text-sm text-secondary">
          Redirecting to {OAUTH_PROVIDERS[loadingProvider].name}...
        </div>
      )}
    </div>
  )
}

import { LoginForm } from "@/components/molecules"
import { UserNavigation } from "@/components/molecules"
import { retrieveCustomer } from "@/lib/data/customer"
import { Suspense } from "react"

interface UserPageProps {
  searchParams: Promise<{
    error?: string
    provider?: string
    message?: string
  }>
}

export default async function UserPage({ searchParams }: UserPageProps) {
  const params = await searchParams
  let user: any = null
  let retrieveError: string | null = null

  console.log('User Page Debug:')
  console.log('- Search params:', params)
  
  // Only try to retrieve customer if there's no OAuth error
  if (!params.error) {
    try {
      console.log('- Attempting to retrieve customer...')
      user = await retrieveCustomer()
      console.log('- Customer retrieved:', user ? `${user.email} (${user.id})` : 'null')
    } catch (error: any) {
      console.error("Error retrieving customer:", error)
      retrieveError = "Failed to load user profile"
    }
  } else {
    console.log('- Skipping customer retrieval due to error:', params.error)
  }

  // Show login form if no user or there are errors
  if (!user || params.error || retrieveError) {
    return (
      <Suspense fallback={<div>Loading...</div>}>
        <LoginFormWithErrors 
          oauthError={params.error}
          provider={params.provider}
          message={params.message}
          retrieveError={retrieveError}
        />
      </Suspense>
    )
  }

  return (
    <main className="max-w-[1200px] mx-auto px-6 md:px-12 py-8">
      <div className="grid grid-cols-1 md:grid-cols-[240px_1fr] gap-8">
        <UserNavigation />
        <div>
          <h1
            className="font-barlow-condensed font-bold"
            style={{ fontSize: 28, color: "var(--text-primary, #F0EEFF)", letterSpacing: "-0.01em" }}
          >
            Welcome {user.first_name}
          </h1>
          <p style={{ fontSize: 15, color: "var(--text-secondary, #B8B0D8)", marginTop: 4 }}>
            Your account is ready to go!
          </p>
        </div>
      </div>
    </main>
  )
}

// Separate component to handle OAuth errors in the login form
function LoginFormWithErrors({
  oauthError,
  provider,
  message,
  retrieveError,
}: {
  oauthError?: string
  provider?: string
  message?: string
  retrieveError?: string | null
}) {
  const getErrorMessage = () => {
    if (retrieveError) {
      return retrieveError
    }

    switch (oauthError) {
      case "invalid_provider":
        return "Invalid OAuth provider selected."
      case "access_denied":
        return `Access was denied for ${provider} authentication. Please try again.`
      case "missing_parameters":
        return `Missing required parameters from ${provider}. Please try again.`
      case "auth_failed":
        return message || `Authentication with ${provider} failed. Please try again.`
      case "oauth_error":
        return message || `An error occurred with ${provider} authentication.`
      case "server_error":
        return message || "A server error occurred during authentication."
      case "missing_token":
        return `Authentication with ${provider} succeeded but no token was received. Please try again.`
      case "unexpected_response":
        return `Unexpected response from ${provider} authentication. Please try again.`
      default:
        if (message) {
          return decodeURIComponent(message)
        }
        return null
    }
  }

  const errorMessage = getErrorMessage()

  return (
    <div>
      {errorMessage && (
        <div className="max-w-md mx-auto mt-6 px-4">
          <div
            className="flex items-start gap-3 p-4 rounded-[14px] mb-6"
            style={{
              background: "rgba(239, 68, 68, 0.06)",
              border: "1px solid rgba(239, 68, 68, 0.2)",
            }}
          >
            <span className="text-lg shrink-0" style={{ color: "var(--negative, #EF4444)" }}>&#10005;</span>
            <div>
              <p className="text-sm font-medium" style={{ color: "var(--text-primary, #F0EEFF)" }}>
                Authentication Error
              </p>
              <p className="text-sm mt-1" style={{ color: "var(--text-secondary, #B8B0D8)" }}>
                {errorMessage}
              </p>
            </div>
          </div>
        </div>
      )}
      <LoginForm />
    </div>
  )
}

"use server"

import { sdk } from "../config"
import { HttpTypes } from "@medusajs/types"
import { revalidateTag } from "next/cache"
import { redirect } from "next/navigation"
import {
  getAuthHeaders,
  getCacheOptions,
  getCacheTag,
  getCartId,
  removeAllAuthCookies,
  removeCartId,
  setAuthToken,
} from "./cookies"

export const retrieveCustomer =
  async (): Promise<HttpTypes.StoreCustomer | null> => {
    const authHeaders = await getAuthHeaders()

    if (!authHeaders || !('authorization' in authHeaders)) {
      return null
    }

    const headers = {
      ...authHeaders,
    }

    const next = {
      ...(await getCacheOptions("customers")),
    }

    return await sdk.client
      .fetch<{ customer: HttpTypes.StoreCustomer }>(`/store/customers/me`, {
        method: "GET",
        query: {
          fields: "*orders",
        },
        headers,
        next,
        cache: "force-cache",
      })
      .then(({ customer }) => customer)
      .catch(() => null)
  }

export interface CustomerProfile {
  customer_id: string
  display_name: string | null
  bio: string | null
  location: string | null
  avatar_url: string | null
  tcg_games: string[] | null
  notify_order_updates: boolean
  notify_price_alerts: boolean
  notify_messages: boolean
  profile_public: boolean
  show_sales_history: boolean
  is_seller: boolean
}

export async function invalidateCustomerProfileCache() {
  revalidateTag('customer-profile')
}

export const getCustomerProfile = async (customerId: string): Promise<CustomerProfile | null> => {
  try {
    const res = await fetch(
      `${process.env.NEXT_PUBLIC_CUSTOMER_BACKEND_URL}/api/customers/${customerId}/profile`,
      { next: { tags: ['customer-profile'], revalidate: 60 } }
    )
    if (!res.ok) return null
    const { data } = await res.json()
    return data as CustomerProfile
  } catch {
    return null
  }
}

export const updateCustomer = async (body: HttpTypes.StoreUpdateCustomer) => {
  const headers = {
    ...(await getAuthHeaders()),
  }

  const updateRes = await sdk.store.customer
    .update(body, {}, headers)
    .then(({ customer }) => customer)
    .catch((err) => {
      throw new Error(err.message)
    })

  const cacheTag = await getCacheTag("customers")
  revalidateTag(cacheTag)

  return updateRes
}

export async function signup(formData: FormData) {
  const password = formData.get("password") as string
  const customerForm = {
    email: formData.get("email") as string,
    first_name: formData.get("first_name") as string,
    last_name: formData.get("last_name") as string,
    phone: formData.get("phone") as string,
  }

  try {
    const token = await sdk.auth.register("customer", "emailpass", {
      email: customerForm.email,
      password: password,
    })

    await setAuthToken(token as string)

    const headers = {
      ...(await getAuthHeaders()),
    }

    const { customer: createdCustomer } = await sdk.store.customer.create(
      customerForm,
      {},
      headers
    )

    const loginToken = await sdk.auth.login("customer", "emailpass", {
      email: customerForm.email,
      password,
    })

    await setAuthToken(loginToken as string)

    // Trigger post-registration side effects: verification email + refresh token + auth event
    const backendUrl = process.env.MEDUSA_BACKEND_URL || 'http://localhost:9000'
    const authHeaders = await getAuthHeaders()
    const postRegisterRes = await fetch(
      `${backendUrl}/store/auth/emailpass/post-register`,
      {
        method: 'POST',
        headers: { ...(authHeaders as Record<string, string>) },
      }
    )
    if (postRegisterRes.ok) {
      // Propagate the refresh token Set-Cookie header to the client
      const refreshCookie = postRegisterRes.headers.get('set-cookie')
      if (refreshCookie) {
        const { cookies } = await import('next/headers')
        const cookieStore = await cookies()
        const match = refreshCookie.match(/_medusa_refresh=([^;]+)/)
        if (match) {
          cookieStore.set('_medusa_refresh', match[1], {
            httpOnly: true,
            secure: process.env.NODE_ENV === 'production',
            sameSite: 'strict',
            maxAge: 30 * 24 * 60 * 60,
            path: '/',
          })
        }
      }
    }

    const customerCacheTag = await getCacheTag("customers")
    revalidateTag(customerCacheTag)

    await transferCart()

    return createdCustomer
  } catch (error: any) {
    return error.toString()
  }
}

export async function login(formData: FormData) {
  const email = formData.get("email") as string
  const password = formData.get("password") as string

  try {
    await sdk.auth
      .login("customer", "emailpass", { email, password })
      .then(async (token) => {
        await setAuthToken(token as string)
        const customerCacheTag = await getCacheTag("customers")
        revalidateTag(customerCacheTag)
      })
  } catch (error: any) {
    // Check if this might be a seller account trying to login
    try {
      await sdk.auth.login("seller", "emailpass", { email, password })
      // If seller login succeeds, return a specific error message
      return "This email is registered as a seller account. Please create a separate customer account to shop on the storefront, or use the vendor panel to manage your store."
    } catch (sellerError) {
      // If both customer and seller login fail, return the original customer error
      return error.toString()
    }
  }

  try {
    await transferCart()
  } catch (error: any) {
    return error.toString()
  }
}

/**
 * Clears all auth state (cookies, caches) without redirecting.
 * Use this in API route handlers where redirect() would throw.
 */
export async function clearSession() {
  try {
    const authHeaders = await getAuthHeaders()

    if (authHeaders && 'authorization' in authHeaders) {
      const bearerToken = (authHeaders as any).authorization

      await fetch(`${process.env.MEDUSA_BACKEND_URL || 'http://localhost:9000'}/auth/logout`, {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
          "Authorization": bearerToken
        }
      }).catch(() => {
        // Logout API call failed — non-critical
      })
    }
  } catch {
    // Error during logout — non-critical
  }

  await removeAllAuthCookies()

  const customerCacheTag = await getCacheTag("customers")
  revalidateTag(customerCacheTag)

  await removeCartId()

  const cartCacheTag = await getCacheTag("carts")
  revalidateTag(cartCacheTag)
}

export async function signout() {
  await clearSession()
  redirect(`/`)
}

export async function transferCart() {
  const cartId = await getCartId()

  if (!cartId) {
    return
  }

  const headers = await getAuthHeaders()

  await sdk.store.cart.transferCart(cartId, {}, headers)

  const cartCacheTag = await getCacheTag("carts")
  revalidateTag(cartCacheTag)
}

export const addCustomerAddress = async (formData: FormData): Promise<any> => {
  const address = {
    address_name: formData.get("address_name") as string,
    first_name: formData.get("first_name") as string,
    last_name: formData.get("last_name") as string,
    company: formData.get("company") as string,
