import { redirect } from "next/navigation"
import { retrieveCustomer } from "@/lib/data/customer"
import { AuthPage } from "@/components/auth/AuthPage"
import { LoginFormContent } from "./LoginFormContent"
import { Suspense } from "react"

interface LoginPageProps {
  searchParams: Promise<{
    error?: string
    provider?: string
    message?: string
  }>
}

export default async function LoginPage({ searchParams }: LoginPageProps) {
  const customer = await retrieveCustomer()

  if (customer) {
    redirect("/user")
  }

  const params = await searchParams

  return (
    <AuthPage mode="login" heading="Welcome back" subtext="Sign in to your account">
      <Suspense>
        <LoginFormContent
          oauthError={params.error}
          provider={params.provider}
          message={params.message}
        />
      </Suspense>
    </AuthPage>
  )
}

"use client"

import {
  FieldError,
  FieldValues,
  FormProvider,
  useForm,
  useFormContext,
} from "react-hook-form"
import { Button } from "@/components/atoms"
import { zodResolver } from "@hookform/resolvers/zod"
import LocalizedClientLink from "@/components/molecules/LocalizedLink/LocalizedLink"
import { LabeledInput } from "@/components/cells"
import {
  loginFormSchema,
  LoginFormData,
} from "@/components/molecules/LoginForm/schema"
import { useState } from "react"
import { login } from "@/lib/data/customer"
import { useRouter } from "next/navigation"
import { SocialLoginButtons } from "@/components/molecules/SocialLoginButtons"

interface LoginFormContentProps {
  oauthError?: string
  provider?: string
  message?: string
}

function getOAuthErrorMessage(
  error?: string,
  provider?: string,
  message?: string
): string | null {
  switch (error) {
    case "invalid_provider":
      return "Invalid OAuth provider selected."
    case "access_denied":
      return `Access was denied for ${provider} authentication. Please try again.`
    case "missing_parameters":
      return `Missing required parameters from ${provider}. Please try again.`
    case "auth_failed":
      return (
        message || `Authentication with ${provider} failed. Please try again.`
      )
    case "oauth_error":
      return message || `An error occurred with ${provider} authentication.`
    case "server_error":
      return message || "A server error occurred during authentication."
    case "missing_token":
      return `Authentication with ${provider} succeeded but no token was received. Please try again.`
    case "unexpected_response":
      return `Unexpected response from ${provider} authentication. Please try again.`
    default:
      if (message) {
        return decodeURIComponent(message)
      }
      return null
  }
}

export function LoginFormContent({
  oauthError,
  provider,
  message,
}: LoginFormContentProps) {
  const methods = useForm<LoginFormData>({
    resolver: zodResolver(loginFormSchema),
    defaultValues: { email: "", password: "" },
  })

  const oauthErrorMessage = getOAuthErrorMessage(oauthError, provider, message)

  return (
    <FormProvider {...methods}>
      <LoginFormInner oauthErrorMessage={oauthErrorMessage} />
    </FormProvider>
  )
}

function LoginFormInner({
  oauthErrorMessage,
}: {
  oauthErrorMessage: string | null
}) {
  const [error, setError] = useState("")
  const [socialError, setSocialError] = useState("")
  const {
    handleSubmit,
    register,
    formState: { errors, isSubmitting },
  } = useFormContext()
  const router = useRouter()

  const submit = async (data: FieldValues) => {
    const formData = new FormData()
    formData.append("email", data.email)
    formData.append("password", data.password)

    const res = await login(formData)
    if (res) {
      setError(res)
      return
    }
    setError("")
    router.push("/user")
  }

  return (
    <div className="space-y-6">
      {/* OAuth error banner */}
      {oauthErrorMessage && (
        <div
          className="flex items-start gap-3 p-4 rounded-[14px]"
          style={{
            background: "rgba(239, 68, 68, 0.06)",
            border: "1px solid rgba(239, 68, 68, 0.2)",
          }}
        >
          <span
            className="text-lg shrink-0"
            style={{ color: "var(--negative, #EF4444)" }}
          >
            &#10005;
          </span>
          <div>
            <p className="text-sm font-medium text-primary">
              Authentication Error
            </p>
            <p className="text-sm mt-1 text-secondary">{oauthErrorMessage}</p>
          </div>
        </div>
      )}

      {/* Social Login */}
      <SocialLoginButtons
        variant="login"
        onError={setSocialError}
        disabled={isSubmitting}
      />

      {socialError && (
        <p className="label-md text-negative text-center">{socialError}</p>
      )}

      {/* Divider */}
      <div className="relative">
        <div className="absolute inset-0 flex items-center">
          <span className="w-full border-t border-default" />
        </div>
        <div className="relative flex justify-center text-sm">
          <span className="px-3 bg-surface-1 text-tertiary">or</span>
        </div>
      </div>

      {/* Email/Password Form */}
      <form onSubmit={handleSubmit(submit)} className="space-y-4">
        <LabeledInput
          label="Email"
          placeholder="you@example.com"
          error={errors.email as FieldError}
          {...register("email")}
        />
        <LabeledInput
          label="Password"
          placeholder="Enter your password"
          type="password"
          error={errors.password as FieldError}
          {...register("password")}
        />
        <div className="flex justify-end">
          <LocalizedClientLink
            href="/user/forgot-password"
            className="text-sm font-medium text-interactive"
          >
            Forgot password?
          </LocalizedClientLink>
        </div>
        {error && <p className="label-md text-negative">{error}</p>}
        <Button
          className="w-full rounded-[14px]"
          disabled={isSubmitting}
          style={{
            background: "var(--brand-primary, #8B5CF6)",
            color: "#fff",
            boxShadow: "0 2px 8px rgba(139, 92, 246, 0.25)",
          }}
        >
          Sign In
        </Button>
      </form>

      {/* Switch link */}
      <p className="text-center text-sm text-secondary">
        Don&apos;t have an account?{" "}
        <LocalizedClientLink href="/register" className="font-semibold text-interactive">
          Sign up
        </LocalizedClientLink>
      </p>

      {/* Terms */}
      <p className="text-center text-[11px] text-tertiary leading-relaxed">
        By continuing, you agree to our{" "}
        <LocalizedClientLink href="/terms" className="text-secondary underline underline-offset-2">
          Terms of Service
        </LocalizedClientLink>{" "}
        and{" "}
        <LocalizedClientLink href="/privacy" className="text-secondary underline underline-offset-2">
          Privacy Policy
        </LocalizedClientLink>
      </p>
    </div>
  )
}

