"use client"

import {
  FieldError,
  FieldValues,
  FormProvider,
  useForm,
  useFormContext,
} from "react-hook-form"
import { Button } from "@/components/atoms"
import { zodResolver } from "@hookform/resolvers/zod"
import LocalizedClientLink from "@/components/molecules/LocalizedLink/LocalizedLink"
import { LabeledInput } from "@/components/cells"
import {
  registerFormSchema,
  RegisterFormData,
} from "@/components/molecules/RegisterForm/schema"
import { signup } from "@/lib/data/customer"
import { useState } from "react"
import { PasswordValidator } from "@/components/cells/PasswordValidator/PasswordValidator"
import { SocialLoginButtons } from "@/components/molecules/SocialLoginButtons"

export function RegisterFormContent() {
  const methods = useForm<RegisterFormData>({
    resolver: zodResolver(registerFormSchema),
    defaultValues: {
      firstName: "",
      lastName: "",
      phone: "",
      email: "",
      password: "",
    },
  })

  return (
    <FormProvider {...methods}>
      <RegisterFormInner />
    </FormProvider>
  )
}

function RegisterFormInner() {
  const [passwordError, setPasswordError] = useState({
    isValid: false,
    lower: false,
    upper: false,
    "8chars": false,
    symbolOrDigit: false,
  })
  const [error, setError] = useState<string | undefined>()
  const [socialError, setSocialError] = useState("")
  const {
    handleSubmit,
    register,
    watch,
    formState: { errors, isSubmitting },
  } = useFormContext()

  const submit = async (data: FieldValues) => {
    const formData = new FormData()
    formData.append("email", data.email)
    formData.append("password", data.password)
    formData.append("first_name", data.firstName)
    formData.append("last_name", data.lastName)
    formData.append("phone", data.phone)

    const res = passwordError.isValid && (await signup(formData))

    if (res && !res?.id) setError(res)
  }

  return (
    <div className="space-y-6">
      {/* Social Login */}
      <SocialLoginButtons
        variant="register"
        onError={setSocialError}
        disabled={isSubmitting}
      />

      {socialError && (
        <p className="label-md text-negative text-center">{socialError}</p>
      )}

      {/* Divider */}
      <div className="relative">
        <div className="absolute inset-0 flex items-center">
          <span className="w-full border-t border-default" />
        </div>
        <div className="relative flex justify-center text-sm">
          <span className="px-3 bg-surface-1 text-tertiary">or</span>
        </div>
      </div>

      {/* Registration Form */}
      <form onSubmit={handleSubmit(submit)} className="space-y-4">
        <div className="flex flex-col md:flex-row gap-4">
          <LabeledInput
            className="md:w-1/2"
            label="First name"
            placeholder="Your first name"
            error={errors.firstName as FieldError}
            {...register("firstName")}
          />
          <LabeledInput
            className="md:w-1/2"
            label="Last name"
            placeholder="Your last name"
            error={errors.lastName as FieldError}
            {...register("lastName")}
          />
        </div>
        <div className="flex flex-col md:flex-row gap-4">
          <LabeledInput
            className="md:w-1/2"
            label="Email"
            placeholder="you@example.com"
            error={errors.email as FieldError}
            {...register("email")}
          />
          <LabeledInput
            className="md:w-1/2"
            label="Phone"
            placeholder="Your phone number"
            error={errors.phone as FieldError}
            {...register("phone")}
          />
        </div>
        <div>
          <LabeledInput
            className="mb-2"
            label="Password"
            placeholder="Create a strong password"
            type="password"
            error={errors.password as FieldError}
            {...register("password")}
          />
          <PasswordValidator
            password={watch("password")}
            setError={setPasswordError}
          />
        </div>

        {error && <p className="label-md text-negative">{error}</p>}
        <Button
          className="w-full rounded-[14px]"
          disabled={isSubmitting}
          loading={isSubmitting}
          style={{
            background: "var(--brand-primary, #8B5CF6)",
            color: "#fff",
            boxShadow: "0 2px 8px rgba(139, 92, 246, 0.25)",
          }}
        >
          Create Account
        </Button>
      </form>

      {/* Switch link */}
      <p className="text-center text-sm text-secondary">
        Already have an account?{" "}
        <LocalizedClientLink href="/login" className="font-semibold text-interactive">
          Sign in
        </LocalizedClientLink>
      </p>

      {/* Terms */}
      <p className="text-center text-[11px] text-tertiary leading-relaxed">
        By continuing, you agree to our{" "}
        <LocalizedClientLink href="/terms" className="text-secondary underline underline-offset-2">
          Terms of Service
        </LocalizedClientLink>{" "}
        and{" "}
        <LocalizedClientLink href="/privacy" className="text-secondary underline underline-offset-2">
          Privacy Policy
        </LocalizedClientLink>
      </p>
    </div>
  )
}

