import { describe, it, expect, vi, beforeEach } from "vitest"
import { render, screen } from "@testing-library/react"
import { AuthPage } from "../AuthPage"
import { AuthBrandPanel } from "../AuthBrandPanel"

// Mock SocialLoginButtons to avoid OAuth import chain
vi.mock("@/components/molecules/SocialLoginButtons", () => ({
  SocialLoginButtons: ({
    variant,
  }: {
    variant: string
    onError?: (e: string) => void
    disabled?: boolean
  }) => (
    <div data-testid="social-login-buttons" data-variant={variant}>
      <button>Continue with Google</button>
      <button>Continue with Discord</button>
      <button>Continue with Microsoft</button>
    </div>
  ),
}))

// Mock next/navigation
vi.mock("next/navigation", () => ({
  useRouter: () => ({ push: vi.fn() }),
  useParams: () => ({ locale: "us" }),
}))

// Mock PasswordValidator
vi.mock("@/components/cells/PasswordValidator/PasswordValidator", () => ({
  PasswordValidator: ({ password }: { password: string }) => (
    <div data-testid="password-validator">Password strength: {password}</div>
  ),
}))

describe("AuthBrandPanel", () => {
  it("renders the SideDecked wordmark", () => {
    render(<AuthBrandPanel />)
    expect(screen.getByText("SideDecked")).toBeTruthy()
  })

  it("renders the tagline", () => {
    render(<AuthBrandPanel />)
    expect(
      screen.getByText("The marketplace for competitive players")
    ).toBeTruthy()
  })

  it("renders game dots for MTG, Pokemon, YGO, One Piece", () => {
    render(<AuthBrandPanel />)
    const gameDots = screen.getByTestId("game-dots")
    expect(gameDots).toBeTruthy()
    expect(screen.getByText("MTG")).toBeTruthy()
    expect(screen.getByText("Pokemon")).toBeTruthy()
    expect(screen.getByText("YGO")).toBeTruthy()
    expect(screen.getByText("One Piece")).toBeTruthy()
  })

  it("renders trust text", () => {
    render(<AuthBrandPanel />)
    expect(
      screen.getByText("Trusted by 10,000+ players across 4 games")
    ).toBeTruthy()
  })

  it("has hidden md:flex class for mobile hiding", () => {
    render(<AuthBrandPanel />)
    const panel = screen.getByTestId("auth-brand-panel")
    expect(panel.className).toContain("hidden")
    expect(panel.className).toContain("md:flex")
  })
})

describe("AuthPage", () => {
  it("renders brand panel and form panel in split-screen", () => {
    render(
      <AuthPage mode="login" heading="Welcome back" subtext="Sign in">
        <div>form content</div>
      </AuthPage>
    )
    expect(screen.getByTestId("auth-brand-panel")).toBeTruthy()
    expect(screen.getByTestId("auth-form-panel")).toBeTruthy()
  })

  it("renders heading and subtext in form panel", () => {
    render(
      <AuthPage mode="login" heading="Welcome back" subtext="Sign in to your account">
        <div>content</div>
      </AuthPage>
    )
    expect(screen.getByText("Welcome back")).toBeTruthy()
    expect(screen.getByText("Sign in to your account")).toBeTruthy()
  })

  it("renders children inside form panel", () => {
    render(
      <AuthPage mode="login" heading="Test" subtext="Sub">
        <div data-testid="child-content">Hello</div>
      </AuthPage>
    )
    const formPanel = screen.getByTestId("auth-form-panel")
    expect(formPanel.querySelector('[data-testid="child-content"]')).toBeTruthy()
  })

  it("sets data-mode attribute", () => {
    render(
      <AuthPage mode="register" heading="Create" subtext="Join">
        <div>content</div>
      </AuthPage>
    )
    const page = screen.getByTestId("auth-page")
    expect(page.getAttribute("data-mode")).toBe("register")
  })

  it("renders mobile logo header (visible on mobile, hidden on md+)", () => {
    render(
      <AuthPage mode="login" heading="Test" subtext="Sub">
        <div>content</div>
      </AuthPage>
    )
    // The mobile header contains the SideDecked text
    // We expect multiple instances: one in brand panel (hidden md:flex), one in mobile header (md:hidden)
    const wordmarks = screen.getAllByText("SideDecked")
    expect(wordmarks.length).toBeGreaterThanOrEqual(2)
  })

  it("brand panel has 55% width class", () => {
    render(
      <AuthPage mode="login" heading="Test" subtext="Sub">
        <div>content</div>
