describe("Voltage token compliance", () => {
  it("AuthPage does not use bg-white or Tailwind gray classes", async () => {
    const fs = await import("fs")
    const path = await import("path")

    const authPagePath = path.resolve(
      __dirname,
      "../AuthPage.tsx"
    )
    const brandPanelPath = path.resolve(
      __dirname,
      "../AuthBrandPanel.tsx"
    )

    const authPageContent = fs.readFileSync(authPagePath, "utf-8")
    const brandPanelContent = fs.readFileSync(brandPanelPath, "utf-8")

    const combined = authPageContent + brandPanelContent

    expect(combined).not.toMatch(/bg-white/)
    expect(combined).not.toMatch(/bg-gray-/)
    expect(combined).not.toMatch(/text-gray-/)
  })
})

